setupProduct.query:
#graphql
  mutation OwnerMetafieldsConnectionArgsProductCreate($product: ProductCreateInput!) {
    productCreate(product: $product) {
      product { id title }
      userErrors { field message }
    }
  }

set.query:
mutation OwnerMetafieldsConnectionArgsSet($metafields: [MetafieldsSetInput!]!) {
  metafieldsSet(metafields: $metafields) {
    metafields {
      namespace
      key
      type
      value
    }
    userErrors {
      field
      message
      code
      elementIndex
    }
  }
}

readAfterSet.query:
query OwnerMetafieldsConnectionArgsRead($id: ID!, $keys: [String!]) {
  product(id: $id) {
    rawKeys: metafields(first: 10, keys: ["bravo", "size"]) {
      nodes {
        namespace
        key
        type
        value
      }
      pageInfo {
        hasNextPage
        hasPreviousPage
      }
    }
    qualifiedKeys: metafields(first: 10, keys: $keys) {
      nodes {
        namespace
        key
        type
        value
      }
      pageInfo {
        hasNextPage
        hasPreviousPage
      }
    }
    reversePage: metafields(first: 2, namespace: "connection_args", reverse: true) {
      nodes {
        namespace
        key
        type
        value
      }
      pageInfo {
        hasNextPage
        hasPreviousPage
      }
    }
  }
}

delete.query:
mutation OwnerMetafieldsConnectionArgsDelete($metafields: [MetafieldIdentifierInput!]!) {
  metafieldsDelete(metafields: $metafields) {
    deletedMetafields {
      ownerId
      namespace
      key
    }
    userErrors {
      field
      message
    }
  }
}

readAfterDelete.query:
query OwnerMetafieldsConnectionArgsPostDelete($id: ID!) {
  product(id: $id) {
    postDeleteKeysReverse: metafields(
      first: 10
      keys: ["connection_args.bravo", "connection_args.charlie"]
      reverse: true
    ) {
      nodes {
        namespace
        key
        type
        value
      }
      pageInfo {
        hasNextPage
        hasPreviousPage
      }
    }
  }
}
